    setTimeout(() => {
      setIsSubmitting(false);
      setIsSuccess(true);
    }, 1500);
  };

  if (isSuccess) {
    return (
      <section className="py-24 bg-surface border-t border-gray-900 flex items-center justify-center min-h-[600px]">
